import { useEffect, useState } from "react"
import { Link } from "react-router-dom"
import Navbar from "../components/Navbar"
import RestaurantCard from "../components/RestaurantCard"
import API from "../api/axios"

export default function History() {
  const [reviews, setReviews] = useState([])
  const [restaurantsAdded, setRestaurantsAdded] = useState([])

  useEffect(() => {
    API.get("/users/me/history")
      .then((res) => {
        const data = res.data || {}

        if (Array.isArray(data)) {
          setReviews(data)
          setRestaurantsAdded([])
          return
        }

        setReviews(Array.isArray(data.reviews) ? data.reviews : [])
        setRestaurantsAdded(
          Array.isArray(data.restaurants_added) ? data.restaurants_added : []
        )
      })
      .catch(() => {
        setReviews([])
        setRestaurantsAdded([])
      })
  }, [])

  return (
    <div className="subpage">
      <Navbar />
      <div className="subpage-spacer"></div>

      <div className="container page-narrow">
        <div className="view-card large-view-card">
          <div className="view-card-header">
            <h2>History</h2>
            <Link to="/profile" className="btn btn-outline">
              Back to Profile
            </Link>
          </div>

          {/* Reviews Section */}
          <div className="history-section">
            <h3>Your Reviews</h3>
            <div className="history-list">
              {reviews.length === 0 && <p>No reviews yet.</p>}

              {reviews.map((review) => (
                <div key={review.review_id} className="history-card">
                  <strong>Restaurant #{review.restaurant_id}</strong>
                  <span>
                    {review.review_date
                      ? new Date(review.review_date).toLocaleString()
                      : ""}
                  </span>
                  <p>Rating: {review.rating}/5</p>
                  <p>{review.comment || "No comment"}</p>

                  <div className="history-actions">
                    <Link
                      to={`/restaurant/${review.restaurant_id}`}
                      className="btn btn-outline"
                    >
                      View Restaurant
                    </Link>
                    <Link
                      to={`/edit-review/${review.review_id}`}
                      className="btn btn-primary"
                    >
                      Edit Review
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Restaurants Added Section (using RestaurantCard) */}
          <div className="history-section">
            <h3>Restaurants You Added</h3>

            {restaurantsAdded.length === 0 && (
              <p>No restaurants added yet.</p>
            )}

            <div className="restaurant-grid">
              {restaurantsAdded.map((restaurant) => (
                <RestaurantCard
                  key={restaurant.restaurant_id}
                  data={restaurant}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}
